.darma-loader-uiverse-flying-file-stream { display: inline-flex; align-items: center; justify-content: center; position: relative; }
.darma-loader-uiverse-flying-file-stream__con {
  position: relative;
  width: 160px;
  height: 100px;
  overflow: hidden;
}

.darma-loader-uiverse-flying-file-stream__pfile {
position: absolute;
bottom: 25px;
width: 40px;
height: 50px;
background: linear-gradient(90deg, var(--loader-color, #b324db), var(--loader-secondary-color, #ac8dcb));
border-radius: 4px;
transform-origin: center;
animation: darma-loader-uiverse-flying-file-stream-flyRight 3s ease-in-out infinite;
opacity: 0;
}

.darma-loader-uiverse-flying-file-stream__pfile::before {
content: "";
position: absolute;
top: 6px;
left: 6px;
width: 28px;
height: 4px;
background-color: #ffffff;
border-radius: 2px;
}

.darma-loader-uiverse-flying-file-stream__pfile::after {
content: "";
position: absolute;
top: 13px;
left: 6px;
width: 18px;
height: 4px;
background-color: #ffffff;
border-radius: 2px;
}

@keyframes darma-loader-uiverse-flying-file-stream-flyRight {
0% {
left: -10%;
transform: scale(0);
opacity: 0;
}
50% {
left: 45%;
transform: scale(1.2);
opacity: 1;
}
100% {
left: 100%;
transform: scale(0);
opacity: 0;
}
}

.darma-loader-uiverse-flying-file-stream__pfile {
animation-delay: calc(var(--i) * 0.6s);
}

